{
  "$schema": "https://json-schema.org/draft/2020-12/schema",
  "$id": "./agent-run.codex-output.schema.json",
  "title": "Codex CLI agent run structured output",
  "type": "object",
  "additionalProperties": false,
  "required": [
    "schema_version",
    "record_type",
    "id",
    "agent_role",
    "agent_id",
    "mode",
    "started_at",
    "completed_at",
    "status",
    "scope",
    "canonical_write_policy",
    "execution",
    "inputs",
    "outputs",
    "quality_checks",
    "blocking_issues",
    "next_actions"
  ],
  "properties": {
    "schema_version": {
      "type": "string",
      "const": "1.0.0"
    },
    "record_type": {
      "type": "string",
      "const": "agent_run"
    },
    "id": {
      "type": "string",
      "pattern": "^[a-z0-9]+[a-z0-9._-]*$"
    },
    "agent_role": {
      "type": "string",
      "enum": [
        "triage_agent",
        "search_agent",
        "screening_agent",
        "dedupe_linker_agent",
        "extraction_agent",
        "trial_registry_agent",
        "classification_agent",
        "risk_of_bias_agent",
        "synthesis_agent",
        "review_agent",
        "supervisor_agent",
        "self_healing_agent",
        "release_agent"
      ]
    },
    "agent_id": {
      "type": "string"
    },
    "mode": {
      "type": "string",
      "enum": [
        "bootstrap",
        "surveillance",
        "coverage_repair",
        "extraction_refresh",
        "synthesis_refresh",
        "agent_directed"
      ]
    },
    "started_at": {
      "type": "string"
    },
    "completed_at": {
      "type": "string"
    },
    "status": {
      "type": "string",
      "enum": [
        "succeeded",
        "partial",
        "failed",
        "blocked"
      ]
    },
    "scope": {
      "type": "object",
      "additionalProperties": false,
      "required": [
        "question",
        "hallmark_ids",
        "track_ids",
        "intervention_ids"
      ],
      "properties": {
        "question": {
          "type": "string"
        },
        "hallmark_ids": {
          "type": "array",
          "items": {
            "type": "string",
            "pattern": "^[a-z0-9]+[a-z0-9._-]*$"
          }
        },
        "track_ids": {
          "type": "array",
          "items": {
            "type": "string",
            "pattern": "^[a-z0-9]+[a-z0-9._-]*$"
          }
        },
        "intervention_ids": {
          "type": "array",
          "items": {
            "type": "string",
            "pattern": "^[a-z0-9]+[a-z0-9._-]*$"
          }
        }
      }
    },
    "canonical_write_policy": {
      "type": "string",
      "enum": [
        "no_canonical_writes",
        "candidate_change_required"
      ]
    },
    "execution": {
      "type": "object",
      "additionalProperties": false,
      "required": [
        "surface",
        "isolation",
        "workspace_path",
        "prompt_file",
        "prompt_template_file",
        "job_file",
        "output_schema_path",
        "output_path",
        "jsonl_log_path",
        "sandbox",
        "approval_policy"
      ],
      "properties": {
        "surface": {
          "type": "string",
          "enum": [
            "interactive_session",
            "codex_exec",
            "codex_cloud",
            "github_action",
            "other"
          ]
        },
        "isolation": {
          "type": "string",
          "enum": [
            "foreground_checkout",
            "git_worktree",
            "codex_managed_worktree",
            "ci_runner",
            "container",
            "other"
          ]
        },
        "workspace_path": {
          "type": "string"
        },
        "prompt_file": {
          "type": "string"
        },
        "prompt_template_file": {
          "type": [
            "string",
            "null"
          ]
        },
        "job_file": {
          "type": [
            "string",
            "null"
          ]
        },
        "output_schema_path": {
          "type": "string"
        },
        "output_path": {
          "type": "string"
        },
        "jsonl_log_path": {
          "type": "string"
        },
        "sandbox": {
          "type": "string",
          "enum": [
            "read-only",
            "workspace-write",
            "danger-full-access",
            "not_applicable"
          ]
        },
        "approval_policy": {
          "type": "string",
          "enum": [
            "never",
            "on-request",
            "untrusted",
            "not_applicable"
          ]
        }
      }
    },
    "inputs": {
      "type": "array",
      "items": {
        "type": "object",
        "additionalProperties": false,
        "required": [
          "input_type",
          "reference",
          "summary"
        ],
        "properties": {
          "input_type": {
            "type": "string",
            "enum": [
              "user_request",
              "plan_item",
              "coverage_gap",
              "candidate_change",
              "source_snapshot",
              "text_snapshot",
              "record",
              "export",
              "other"
            ]
          },
          "reference": {
            "type": "string"

          },
          "summary": {
            "type": "string"
          }
        }
      }
    },
    "outputs": {
      "anyOf": [
        {
          "type": "object",
          "additionalProperties": false,
          "required": [
            "summary",
            "research_session_id",
            "search_log_id",
            "screening_run_id",
            "generated_files",
            "export_paths"
          ],
          "properties": {
            "summary": {
              "type": "string"
            },
            "research_session_id": {
              "type": [
                "string",
                "null"
              ],
              "pattern": "^[a-z0-9]+[a-z0-9._-]*$"
            },
            "search_log_id": {
              "type": [
                "string",
                "null"
              ],
              "pattern": "^[a-z0-9]+[a-z0-9._-]*$"
            },
            "screening_run_id": {
              "type": [
                "string",
                "null"
              ],
              "pattern": "^[a-z0-9]+[a-z0-9._-]*$"
            },
            "generated_files": {
              "type": "array",
              "items": {
                "type": "string"
              }
            },
            "export_paths": {
              "type": "array",
              "items": {
                "type": "string"
              }
            }
          }
        },
        {
          "type": "object",
          "additionalProperties": false,
          "required": [
            "summary",
            "research_session_id",
            "search_log_id",
            "screening_run_id",
            "candidate_change_id",
            "proposed_records",
            "generated_files",
            "export_paths"
          ],
          "properties": {
            "summary": {
              "type": "string"
            },
            "research_session_id": {
              "type": [
                "string",
                "null"
              ],
              "pattern": "^[a-z0-9]+[a-z0-9._-]*$"
            },
            "search_log_id": {
              "type": [
                "string",
                "null"
              ],
              "pattern": "^[a-z0-9]+[a-z0-9._-]*$"
            },
            "screening_run_id": {
              "type": [
                "string",
                "null"
              ],
              "pattern": "^[a-z0-9]+[a-z0-9._-]*$"
            },
            "candidate_change_id": {
              "type": "string",
              "pattern": "^[a-z0-9]+[a-z0-9._-]*$"
            },
            "proposed_records": {
              "type": "array",
              "items": {
                "type": "object",
                "additionalProperties": false,
                "required": [
                  "record_type",
                  "record_id",
                  "path",
                  "change_type",
                  "rationale"
                ],
                "properties": {
                  "record_type": {
                    "type": "string"
                  },
                  "record_id": {
                    "type": "string",
                    "pattern": "^[a-z0-9]+[a-z0-9._-]*$"
                  },
                  "path": {
                    "type": "string"
                  },
                  "change_type": {
                    "type": "string",
                    "enum": [
                      "create",
                      "release_accept",
                      "update",
                      "delete"
                    ]
                  },
                  "rationale": {
                    "type": "string"
                  }
                }
              }
            },
            "generated_files": {
              "type": "array",
              "items": {
                "type": "string"
              }
            },
            "export_paths": {
              "type": "array",
              "items": {
                "type": "string"
              }
            }
          }
        }
      ]
    },
    "quality_checks": {
      "type": "array",
      "items": {
        "type": "object",
        "additionalProperties": false,
        "required": [
          "check_name",
          "status",
          "summary"
        ],
        "properties": {
          "check_name": {
            "type": "string"
          },
          "status": {
            "type": "string",
            "enum": [
              "passed",
              "failed",
              "not_run"
            ]
          },
          "summary": {
            "type": "string"
          }
        }
      }
    },
    "blocking_issues": {
      "type": "array",
      "items": {
        "type": "string"
      }
    },
    "next_actions": {
      "type": "array",
      "items": {
        "type": "string"
      }
    }
  }
}

{
  "$schema": "https://json-schema.org/draft/2020-12/schema",
  "$id": "./agent-run.schema.json",
  "title": "Agent run output",
  "type": "object",
  "additionalProperties": false,
  "required": [
    "schema_version",
    "record_type",
    "id",
    "agent_role",
    "agent_id",
    "started_at",
    "completed_at",
    "status",
    "scope",
    "canonical_write_policy",
    "outputs",
    "quality_checks"
  ],
  "allOf": [
    {
      "if": {
        "properties": {
          "canonical_write_policy": {
            "const": "candidate_change_required"
          }
        },
        "required": [
          "canonical_write_policy"
        ]
      },
      "then": {
        "required": [
          "outputs"
        ],
        "properties": {
          "outputs": {
            "type": "object",
            "required": [
              "candidate_change_id",
              "proposed_records"
            ],
            "properties": {
              "candidate_change_id": true,
              "proposed_records": true
            }
          }
        }
      }
    }
  ],
  "properties": {
    "schema_version": {
      "const": "1.0.0"
    },
    "record_type": {
      "const": "agent_run"
    },
    "id": {
      "$ref": "./common.schema.json#/$defs/agentRunRef"
    },
    "agent_role": {
      "enum": [
        "triage_agent",
        "search_agent",
        "screening_agent",
        "dedupe_linker_agent",
        "extraction_agent",
        "trial_registry_agent",
        "classification_agent",
        "risk_of_bias_agent",
        "synthesis_agent",
        "review_agent",
        "supervisor_agent",
        "self_healing_agent",
        "release_agent"
      ]
    },
    "agent_id": {
      "type": "string"
    },
    "mode": {
      "$ref": "./common.schema.json#/$defs/researchMode"
    },
    "started_at": {
      "$ref": "./common.schema.json#/$defs/dateTime"
    },
    "completed_at": {
      "$ref": "./common.schema.json#/$defs/dateTime"
    },
    "status": {
      "enum": [
        "succeeded",
        "partial",
        "failed",
        "blocked"
      ]
    },
    "scope": {
      "type": "object",
      "additionalProperties": false,
      "required": [
        "question"
      ],
      "properties": {
        "question": {
          "type": "string"
        },
        "hallmark_ids": {
          "type": "array",
          "items": {
            "$ref": "./common.schema.json#/$defs/hallmarkRef"
          },
          "uniqueItems": true
        },
        "track_ids": {
          "type": "array",
          "items": {
            "$ref": "./common.schema.json#/$defs/trackRef"
          },
          "uniqueItems": true
        },
        "intervention_ids": {
          "type": "array",
          "items": {
            "$ref": "./common.schema.json#/$defs/identifier"
          },
          "uniqueItems": true
        }
      }
    },
    "canonical_write_policy": {
      "enum": [
        "no_canonical_writes",
        "candidate_change_required"
      ]
    },
    "execution": {
      "type": "object",
      "additionalProperties": false,
      "required": [
        "surface",
        "isolation",
        "sandbox",
        "approval_policy"
      ],
      "properties": {
        "surface": {
          "enum": [
            "interactive_session",
            "codex_exec",
            "codex_cloud",
            "github_action",
            "other"
          ]
        },
        "isolation": {
          "enum": [
            "foreground_checkout",
            "git_worktree",
            "codex_managed_worktree",
            "ci_runner",
            "container",
            "other"
          ]
        },
        "workspace_path": {
          "type": "string"
        },
        "prompt_file": {
          "type": "string"
        },
        "prompt_template_file": {
          "type": "string"
        },
        "job_file": {
          "type": "string"
        },
        "output_schema_path": {
          "type": "string"
        },
        "output_path": {
          "type": "string"
        },
        "jsonl_log_path": {
          "type": "string"
        },
        "sandbox": {
          "enum": [
            "read-only",
            "workspace-write",
            "danger-full-access",
            "not_applicable"
          ]
        },
        "approval_policy": {
          "enum": [
            "never",
            "on-request",
            "untrusted",
            "not_applicable"
          ]
        },
        "command": {
          "type": "array",
          "items": {
            "type": "string"
          }
        }
      }
    },
    "inputs": {
      "type": "array",
      "items": {
        "type": "object",
        "additionalProperties": false,
        "required": [
          "input_type",
          "reference"
        ],
        "properties": {
          "input_type": {
            "enum": [
              "user_request",
              "plan_item",
              "coverage_gap",
              "candidate_change",
              "source_snapshot",
              "text_snapshot",
              "record",
              "export",
              "other"
            ]
          },
          "reference": {
            "type": "string"
          },
          "summary": {
            "type": "string"

          }
        }
      }
    },
    "outputs": {
      "type": "object",
      "additionalProperties": false,
      "required": [
        "summary"
      ],
      "properties": {
        "summary": {
          "type": "string"
        },
        "research_session_id": {
          "allOf": [
            {
              "$ref": "./common.schema.json#/$defs/identifier"
            },
            {
              "not": {
                "enum": [
                  "none",
                  "n/a",
                  "na",
                  "null",
                  "unknown",
                  "not_applicable",
                  "not-applicable"
                ]
              }
            }
          ]
        },
        "search_log_id": {
          "allOf": [
            {
              "$ref": "./common.schema.json#/$defs/identifier"
            },
            {
              "not": {
                "enum": [
                  "none",
                  "n/a",
                  "na",
                  "null",
                  "unknown",
                  "not_applicable",
                  "not-applicable"
                ]
              }
            }
          ]
        },
        "screening_run_id": {
          "allOf": [
            {
              "$ref": "./common.schema.json#/$defs/identifier"
            },
            {
              "not": {
                "enum": [
                  "none",
                  "n/a",
                  "na",
                  "null",
                  "unknown",
                  "not_applicable",
                  "not-applicable"
                ]
              }
            }
          ]
        },
        "candidate_change_id": {
          "$ref": "./common.schema.json#/$defs/candidateChangeRef"
        },
        "proposed_records": {
          "type": "array",
          "items": {
            "type": "object",
            "additionalProperties": false,
            "required": [
              "record_type",
              "record_id",
              "path",
              "change_type",
              "rationale"
            ],
            "properties": {
              "record_type": {
                "type": "string"
              },
              "record_id": {
                "$ref": "./common.schema.json#/$defs/identifier"
              },
              "path": {
                "type": "string"
              },
              "change_type": {
                "enum": [
                  "create",
                  "release_accept",
                  "update",
                  "delete"
                ]
              },
              "rationale": {
                "type": "string"
              }
            }
          }
        },
        "generated_files": {
          "type": "array",
          "items": {
            "type": "string"
          },
          "uniqueItems": true
        },
        "export_paths": {
          "type": "array",
          "items": {
            "type": "string"
          },
          "uniqueItems": true
        }
      }
    },
    "quality_checks": {
      "type": "array",
      "items": {
        "type": "object",
        "additionalProperties": false,
        "required": [
          "check_name",
          "status",
          "summary"
        ],
        "properties": {
          "check_name": {
            "type": "string"
          },
          "status": {
            "enum": [
              "passed",
              "failed",
              "not_run"
            ]
          },
          "summary": {
            "type": "string"
          }
        }
      }
    },
    "blocking_issues": {
      "type": "array",
      "items": {
        "type": "string"
      }
    },
    "next_actions": {
      "type": "array",
      "items": {
        "type": "string"
      }
    }
  }
}

{
  "$schema": "https://json-schema.org/draft/2020-12/schema",
  "$id": "./evidence-review.schema.json",
  "title": "Evidence review",
  "type": "object",
  "additionalProperties": false,
  "required": [
    "schema_version",
    "record_type",
    "id",
    "candidate_change_id",
    "review_lane",
    "reviewer_kind",
    "status",
    "verdict",
    "blocking",
    "summary",
    "findings"
  ],
  "properties": {
    "schema_version": {
      "const": "1.0.0"
    },
    "record_type": {
      "const": "evidence_review"
    },
    "id": {
      "$ref": "./common.schema.json#/$defs/evidenceReviewRef"
    },
    "candidate_change_id": {
      "$ref": "./common.schema.json#/$defs/candidateChangeRef"
    },
    "review_lane": {
      "enum": [
        "source_fidelity",
        "extraction_fidelity",
        "taxonomy_mapping",
        "synthesis_boundary",
        "safety_limitations"
      ]
    },
    "reviewer_kind": {
      "enum": [
        "agent",
        "supervisor_agent",
        "system"
      ]
    },
    "reviewer_id": {
      "type": "string"
    },
    "status": {
      "enum": [
        "draft",
        "complete",
        "superseded"
      ]
    },
    "verdict": {
      "enum": [
        "accept",
        "needs_revision",
        "reject"
      ]
    },
    "blocking": {
      "type": "boolean"
    },
    "summary": {
      "type": "string"
    },
    "findings": {
      "type": "array",
      "items": {
        "type": "object",
        "additionalProperties": false,
