          "category",
          "claim_or_issue",
          "why_it_matters",
          "recommended_action",
          "resolution_status"
        ],
        "properties": {
          "finding_id": {
            "$ref": "./common.schema.json#/$defs/identifier"
          },
          "severity": {
            "enum": [
              "critical",
              "major",
              "minor",
              "note"
            ]
          },
          "category": {
            "enum": [
              "source_mismatch",
              "extraction_error",
              "endpoint_boundary",
              "interpretation_overreach",
              "missing_caveat",
              "taxonomy_mapping",
              "safety_limitation",
              "other"
            ]
          },
          "claim_or_issue": {
            "type": "string"
          },
          "why_it_matters": {
            "type": "string"
          },
          "recommended_action": {
            "type": "string"
          },
          "resolution_status": {
            "enum": [
              "open",
              "addressed",
              "closed"
            ]
          }
        }
      }
    }
  }
}

{
  "$schema": "https://json-schema.org/draft/2020-12/schema",
  "$id": "./result.schema.json",
  "title": "Result record",
  "type": "object",
  "additionalProperties": false,
  "required": [
    "schema_version",
    "record_type",
    "id",
    "source_id",
    "study_id",
    "outcome_id",
    "result_type",
    "direction",
    "evidence_tier",
    "confidence",
    "statement"
  ],
  "properties": {
    "schema_version": {
      "const": "1.0.0"
    },
    "record_type": {
      "const": "result"
    },
    "id": {
      "$ref": "./common.schema.json#/$defs/resultRef"
    },
    "name": {
      "type": "string"
    },
    "source_id": {
      "$ref": "./common.schema.json#/$defs/sourceRef"
    },
    "study_id": {
      "$ref": "./common.schema.json#/$defs/studyRef"
    },
    "outcome_id": {
      "$ref": "./common.schema.json#/$defs/outcomeRef"
    },
    "finding_ids": {
      "type": "array",
      "items": {
        "$ref": "./common.schema.json#/$defs/findingRef"
      },
      "uniqueItems": true
    },
    "intervention_ids": {
      "type": "array",
      "items": {
        "$ref": "./common.schema.json#/$defs/identifier"
      },
      "uniqueItems": true
    },
    "comparator": {
      "type": "string"
    },
    "arm_details": {
      "type": "string"
    },
    "sample_size": {
      "type": "integer",
      "minimum": 0
    },
    "group_values": {
      "type": "array",
      "items": {
        "type": "object",
        "additionalProperties": false,
        "required": [
          "group_id",
          "group_label",
          "value"
        ],
        "properties": {
          "group_id": {
            "type": "string"
          },
          "group_label": {
            "type": "string"
          },
          "sample_size": {
            "type": "integer",
            "minimum": 0
          },
          "statistic": {
            "enum": [
              "mean",
              "median",
              "count",
              "percent",
              "other"
            ]
          },
          "value": {
            "type": "number"
          },
          "lower_limit": {
